11	// Synchronous DMI bus abstraction. The real implementation drives the
12	// platform's AHB manager and blocks until each transaction completes; tests
13	// inject a recorder to inspect the op sequence.
14	struct DmiBus
15	{
16	  virtual ~DmiBus() = default;
17	  virtual void write(uint8_t reg, uint32_t value) = 0;
18	  virtual auto read(uint8_t reg) -> uint32_t = 0;
19	};
20	
21	class ResumeDriver
22	{
23	public:
24	  // RISC-V Debug Spec 1.0 register addresses.
25	  static constexpr uint8_t kData0      = 0x04;
26	  static constexpr uint8_t kData1      = 0x05;
27	  static constexpr uint8_t kDmcontrol  = 0x10;
28	  static constexpr uint8_t kDmstatus   = 0x11;
29	  static constexpr uint8_t kAbstractcs = 0x16;
30	  static constexpr uint8_t kCommand    = 0x17;
31	
32	  static constexpr uint16_t kCsrDpc = 0x7B1;
33	
34	  static constexpr uint32_t kDmcontrolDmactive  = 1u << 0;
35	  static constexpr uint32_t kDmcontrolResumereq = 1u << 30;
36	  static constexpr uint32_t kDmcontrolHaltreq   = 1u << 31;
37	
38	  static constexpr uint32_t kDmstatusAllhalted    = 1u << 9;
39	  static constexpr uint32_t kDmstatusAllresumeack = 1u << 17;
40	
41	  static constexpr uint32_t kAbstractcsBusy = 1u << 12;
42	
43	  // The poll budget keeps a buggy DM from hanging the host process.
44	  static constexpr unsigned kPollIterations = 1024;
45	
46	  explicit ResumeDriver(DmiBus& bus)
47	      : bus_{bus}
48	  {}
49	
50	  void resume(const hybrid_state_v1& state)
51	  {
52	    if (state.magic != HYBRID_STATE_MAGIC)
53	      throw std::runtime_error("ResumeDriver::resume: bad magic");
54	    if (state.version != HYBRID_STATE_VERSION)
55	      throw std::runtime_error("ResumeDriver::resume: unsupported version");
56	
57	    // Bring the DM out of reset before any other DMCONTROL bit is honored
58	    // (RISC-V Debug Spec: dmactive must transition 0->1 in its own write).
59	    bus_.write(kDmcontrol, kDmcontrolDmactive);
60	    request_halt();
61	    poll_until_set(kDmstatus, kDmstatusAllhalted);
62	
63	    for (uint16_t i = 0; i < 32; ++i)
64	      write_64bit_register(regno_gpr(i), state.gpr[i]);
65	
66	    write_64bit_register(regno_csr(kCsrDpc), state.pc);
67	
68	    request_resume();
69	    poll_until_set(kDmstatus, kDmstatusAllresumeack);
70	  }
71	
72	private:
73	  void request_halt()
74	  {
75	    bus_.write(kDmcontrol, kDmcontrolDmactive | kDmcontrolHaltreq);
76	  }
77	
78	  void request_resume()
79	  {
80	    bus_.write(kDmcontrol, kDmcontrolDmactive | kDmcontrolResumereq);
81	  }
82	
83	  void write_64bit_register(uint16_t regno, uint64_t value)
84	  {
85	    bus_.write(kData0, uint32_t(value & 0xffffffffu));
86	    bus_.write(kData1, uint32_t((value >> 32) & 0xffffffffu));
87	    bus_.write(kCommand,
88	               access_register_command(regno, AarSize::Bits64, /*write=*/true));
89	    poll_until_clear(kAbstractcs, kAbstractcsBusy);
90	  }
91	
92	  void poll_until_set(uint8_t reg, uint32_t mask)
93	  {
94	    for (unsigned i = 0; i < kPollIterations; ++i)
95	      if ((bus_.read(reg) & mask) == mask) return;
96	    throw std::runtime_error("ResumeDriver: poll_until_set timed out");
97	  }
98	
99	  void poll_until_clear(uint8_t reg, uint32_t mask)
100	  {
101	    for (unsigned i = 0; i < kPollIterations; ++i)
102	      if ((bus_.read(reg) & mask) == 0) return;
103	    throw std::runtime_error("ResumeDriver: poll_until_clear timed out");
104	  }
105	
106	  DmiBus& bus_;
107	};
108	
109	}  // namespace hybrid
