13	// Drives the platform's DMI AHB manager synchronously. Each read/write blocks
14	// (advancing SystemC time) until the transaction reaches okay or error.
15	template<std::size_t AddrWidth, std::size_t DataWidth>
16	class SystemCDmiBus final : public DmiBus
17	{
18	public:
19	  using ahb_manager = ahb::manager<AddrWidth, DataWidth>;
20	
21	  SystemCDmiBus(ahb_manager& ahb, const sc_core::sc_time& cycle)
22	      : ahb_{ahb}, cycle_{cycle}
23	  {}
24	
25	  void write(uint8_t reg, uint32_t value) override
26	  {
27	    static_cast<void>(ahb_.write(typename ahb_manager::addr_type(reg << 2),
28	                                 typename ahb_manager::data_type(value)));
29	    drain();
30	  }
31	
32	  auto read(uint8_t reg) -> uint32_t override
33	  {
34	    ahb_.read(typename ahb_manager::addr_type(reg << 2));
35	    drain();
36	    return uint32_t(ahb_.txn.data.to_uint64());
37	  }
38	
39	private:
40	  void drain()
41	  {
42	    while (ahb_.txn.is_busy()) sc_core::sc_start(cycle_);
43	    if (ahb_.txn.phase == ahb_manager::transaction::phase::error)
44	      throw std::runtime_error("SystemCDmiBus: DMI transaction error");
45	  }
46	
47	  ahb_manager& ahb_;
48	  sc_core::sc_time cycle_;
49	};
50	
51	}  // namespace hybrid
