19	enum class jtag_state
20	{
21	  test_logic_reset,
22	  run_test_idle,
23	  select_dr_scan,
24	  capture_dr,
25	  shift_dr,
26	  exit1_dr,
27	  pause_dr,
28	  exit2_dr,
29	  update_dr,
30	  select_ir_scan,
31	  capture_ir,
32	  shift_ir,
33	  exit1_ir,
34	  pause_ir,
35	  exit2_ir,
36	  update_ir,
37	};
