39	enum class jtag_ir : uint8_t
40	{
41	  idcode = 0x1,
42	  dtmcs = 0x10,
43	  dmi = 0x11,
44	  bypass = uint8_t(-1),
45	};
46	
47	constexpr auto jtag_state_transitions =
48	  std::array<std::array<jtag_state, 2>, 16>{{
49	    // clang-format off
50	    {jtag_state::run_test_idle, jtag_state::test_logic_reset}, // test_logic_reset
51	    {jtag_state::run_test_idle, jtag_state::select_dr_scan}, // run_test_idle
52	    {jtag_state::capture_dr, jtag_state::select_ir_scan}, // select_dr_scan
53	    {jtag_state::shift_dr, jtag_state::exit1_dr}, // capture_dr
54	    {jtag_state::shift_dr, jtag_state::exit1_dr}, // shift_dr
55	    {jtag_state::pause_dr, jtag_state::update_dr}, // exit1_dr
56	    {jtag_state::pause_dr, jtag_state::exit2_dr}, // pause_dr
57	    {jtag_state::shift_dr, jtag_state::update_dr}, // exit2_dr
58	    {jtag_state::run_test_idle, jtag_state::select_dr_scan}, // update_dr
59	    {jtag_state::capture_ir, jtag_state::test_logic_reset}, // select_ir_scan
60	    {jtag_state::shift_ir, jtag_state::exit1_ir}, // capture_ir
61	    {jtag_state::shift_ir, jtag_state::exit1_ir}, // shift_ir
62	    {jtag_state::pause_ir, jtag_state::update_ir}, // exit1_ir
63	    {jtag_state::pause_ir, jtag_state::exit2_ir}, // pause_ir
64	    {jtag_state::shift_ir, jtag_state::update_ir}, // exit2_ir
65	    {jtag_state::run_test_idle, jtag_state::select_dr_scan} // update_ir
66	    // clang-format on
67	  }}; // update_ir
