69	enum class dmi_op_operation
70	{
71	  nop = 0,
72	  read = 1,
73	  write = 2,
74	  reserved = 3,
75	};
76	
77	constexpr static inline auto
78	to_string(const dmi_op_operation op) -> std::string_view
79	{
80	  switch (op) {
81	  case dmi_op_operation::nop:
82	    return "nop";
83	  case dmi_op_operation::read:
84	    return "read";
85	  case dmi_op_operation::write:
86	    return "write";
87	  case dmi_op_operation::reserved:
88	    return "reserved";
89	  default:
90	    __builtin_unreachable();
91	  }
92	}
93	
94	enum class dmi_op_status
95	{
96	  success = 0,
97	  reserved = 1,
98	  failed = 2,
99	  busy = 3,
100	};
101	
102	constexpr static inline auto
103	to_string(const dmi_op_status status) -> std::string_view
104	{
105	  switch (status) {
106	  case dmi_op_status::success:
107	    return "success";
108	  case dmi_op_status::reserved:
