47	template<std::size_t BusWidth = 32>
48	class SimControl : public sc_core::sc_module
49	{
50	public:
51	  using sys_func_ptr = uint64_t (SimControl::*)(
52	    uint64_t, uint64_t, uint64_t, uint64_t, uint64_t, uint64_t, uint64_t);
53	
54	  tlm_utils::simple_target_socket<SimControl, BusWidth> socket{"tsck"};
55	  int32_t exits;
56	  const MemoryRegion region;
57	
58	  SimControl(const sc_core::sc_module_name& name,
59	             const MemoryRegion& region,
60	             SimpleMemory<BusWidth>& main_memory,
61	             sc_core::sc_signal<sc_dt::sc_uint<31>>& int_trigger,
62	             const sc_core::sc_clock& clk)
63	      : sc_core::sc_module{name},
64	        exits(-1),
65	        region(region),
66	        data_region(main_memory),
67	        int_trigger(int_trigger),
68	        clk(clk),
69	        riscv_xlen(0),
70	        partial_htif_command(0),
71	        htif_parts_received(0)
72	  {
73	    sim_syscall_table[5] = &SimControl::handle_gettimeofday;
74	    sim_syscall_table[6] = &SimControl::handle_open;
75	    sim_syscall_table[7] = &SimControl::handle_write;
76	    sim_syscall_table[8] = &SimControl::handle_getcwd;
77	    sim_syscall_table[9] = &SimControl::handle_lseek;
78	    sim_syscall_table[10] = &SimControl::handle_read;
79	    sim_syscall_table[11] = &SimControl::handle_flen;
80	    sim_syscall_table[12] = &SimControl::handle_close;
81	    sim_syscall_table[13] = &SimControl::handle_access;
82	    sim_syscall_table[14] = &SimControl::handle_faccessat;
83	    sim_syscall_table[15] = &SimControl::handle_fstat;
84	    sim_syscall_table[16] = &SimControl::handle_fstatat;
85	    sim_syscall_table[17] = &SimControl::handle_link;
86	    sim_syscall_table[18] = &SimControl::handle_lstat;
