27	template<typename CPU>
28	class Simulator : sc_core::sc_module
29	{
30	  using PLATFORM = Platform<platform_config<CPU>>;
31	  static constexpr bool is_axi = (CPU::SYSTEM_BUS_TYPE == BusTypes::AXI);
32	  static constexpr auto bus_width = PLATFORM::data_width;
33	
34	  // Helper: create an AXI→TLM bridge, bind clock, connect initiator BFM
35	  auto make_axi_to_tlm(const char* name, auto& bfm_socket)
36	    -> std::unique_ptr<axi_to_tlm_bridge<bus_width>>
37	  {
38	    auto bridge = std::make_unique<axi_to_tlm_bridge<bus_width>>(name);
39	    bridge->pe.clk_i.bind(platform.clk);
40	    bfm_socket.bind(bridge->axi_tsck);
41	    return bridge;
42	  }
43	
44	  // Helper: create a TLM→AXI bridge, bind clock, connect target BFM
45	  auto make_tlm_to_axi(const char* name, auto& bfm_socket)
46	    -> std::unique_ptr<tlm_to_axi_bridge<bus_width>>
47	  {
48	    auto bridge = std::make_unique<tlm_to_axi_bridge<bus_width>>(name);
49	    bridge->pe.clk_i.bind(platform.clk);
50	    bridge->axi_isck.bind(bfm_socket);
51	    return bridge;
52	  }
53	
54	public:
55	  CPU cpu;
56	  PLATFORM platform;
57	
58	  // AXI bridges (only used when is_axi == true, null otherwise)
59	  std::unique_ptr<axi_to_tlm_bridge<bus_width>> mem_bridge;
60	  std::unique_ptr<axi_to_tlm_bridge<bus_width>> mmio_bridge;
61	  std::unique_ptr<tlm_to_axi_bridge<bus_width>> hvm_bridge;
62	  std::unique_ptr<tlm_to_axi_bridge<bus_width>> slv_bridge;
63	
64	  // sys bus (64-bit slave port on CPU, needs width adapter to 256-bit
65	  // interconnect)
66	  static constexpr std::size_t sys_bus_width = 64;
67	  std::unique_ptr<socket_width_adapter<bus_width, sys_bus_width>> sys_adapter;
68	  std::unique_ptr<tlm_to_axi_bridge<sys_bus_width>> sys_bridge;
69	
70	#if _NDS_IOCP_NUM > 0
71	  // iocp_master connects directly to CPU, not through the interconnect.
72	  // It needs to speak the CPU's bus protocol.
73	  using IocpInitiatorType = std::
74	    conditional_t<is_axi, AxiPeInitiator<bus_width>, AhbPeInitiator<bus_width>>;
75	  IocpInitiatorType iocp_master;
76	#endif // _NDS_IOCP_NUM
