90	  Simulator(const sc_core::sc_module_name& name,
91	            std::span<uint8_t> ram_buffer = {})
92	      : sc_core::sc_module{name},
93	        platform("platform", ram_buffer),
94	        dtm(platform.dtm)
95	  {
96	    cpu.bind(platform.clk, platform.resetn, platform.reset_vector,
97	             platform.dmi_signals, platform.wfi_signal, platform.int_trigger);
98	
99	    // --- CPU memory BFM → interconnect ---
100	    if constexpr (is_axi) {
101	      mem_bridge = make_axi_to_tlm("mem_bridge", cpu.mem_bfm.isckt);
102	      platform.interconnect.bind_initiator(mem_bridge->tlm_isck);
103	    } else {
104	      platform.interconnect.bind_initiator(cpu.mem_bfm.isckt);
105	    }
106	
107	    // --- CPU MMIO BFM → interconnect ---
108	    if constexpr (requires { cpu.mmio_bfm; }) {
109	      if constexpr (is_axi) {
110	        mmio_bridge = make_axi_to_tlm("mmio_bridge", cpu.mmio_bfm.isckt);
111	        platform.interconnect.bind_initiator(mmio_bridge->tlm_isck);
112	      } else {
113	        platform.interconnect.bind_initiator(cpu.mmio_bfm.isckt);
114	      }
115	    }
116	
117	    // --- CPU HVM subordinate port ---
118	    if constexpr (requires { cpu.hvm_bfm; }) {
119	      if constexpr (is_axi) {
120	        hvm_bridge = make_tlm_to_axi("hvm_bridge", cpu.hvm_bfm.tsckt);
121	        platform.interconnect.bind_target(
122	          hvm_bridge->tlm_tsck,
123	          {CPU::NDS_HVM_BASE,
124	           CPU::NDS_HVM_BASE + CPU::NDS_HVM_SIZE_KB * 0x1000 - 1});
125	      } else {
126	        platform.interconnect.bind_target(
127	          cpu.hvm_bfm.tsckt,
128	          {CPU::NDS_HVM_BASE,
129	           CPU::NDS_HVM_BASE + CPU::NDS_HVM_SIZE_KB * 0x1000 - 1});
130	      }
131	      platform.custom_master.hvm_base = CPU::NDS_HVM_BASE;
132	    }
133	
134	    // --- CPU slave port ---
135	    if constexpr (requires { cpu.slv_bfm; }) {
136	      if constexpr (is_axi) {
137	        slv_bridge = make_tlm_to_axi("slv_bridge", cpu.slv_bfm.tsckt);
138	        platform.interconnect.bind_target(slv_bridge->tlm_tsck,
139	                                          {HART0_ILM_BASE, HART0_DLM_END});
140	      } else {
141	        platform.interconnect.bind_target(cpu.slv_bfm.tsckt,
142	                                          {HART0_ILM_BASE, HART0_DLM_END});
143	      }
144	      platform.custom_master.ilm_base = HART0_ILM_BASE;
145	      platform.custom_master.dlm_base = HART0_DLM_BASE;
146	    }
147	
148	    // --- CPU sys bus (slave port, 64-bit) → interconnect ---
149	    if constexpr (requires { cpu.sys_bfm; }) {
150	      sys_adapter =
151	        std::make_unique<socket_width_adapter<bus_width, sys_bus_width>>(
152	          "sys_adapter");
153	      sys_bridge =
154	        std::make_unique<tlm_to_axi_bridge<sys_bus_width>>("sys_bridge");
155	      sys_bridge->pe.clk_i.bind(platform.clk);
156	      sys_bridge->axi_isck.bind(cpu.sys_bfm.tsckt);
157	      sys_adapter->isck.bind(sys_bridge->tlm_tsck);
158	      platform.interconnect.bind_target(sys_adapter->tsck,
159	                                        {MLIF_BASE, SLIF_END});
160	    }
161	
162	#if _NDS_IOCP_NUM > 0
163	    iocp_master.protocol_engine.clk_i.bind(platform.clk);
164	    iocp_master.socket.bind(cpu.iocp_bfm.tsckt);
165	#endif // _NDS_IOCP_NUM
