229	  void load_image(const std::string& path, MEM_TYPE type)
230	  {
231	    switch (type) {
232	    case MEM_TYPE::ILM:
233	      if constexpr (requires { cpu.set_ilm({}); }) {
234	        read_binary_file(path, [this](const auto& data) { cpu.set_ilm(data); });
235	      } else {
236	        throw std::runtime_error(
237	          "CPU does not support ILM - cannot load ILM ROM image");
238	      }
239	      break;
240	
241	    case MEM_TYPE::DLM:
242	      if constexpr (requires { cpu.set_dlm({}); }) {
243	        read_binary_file(path, [this](const auto& data) { cpu.set_dlm(data); });
244	      } else {
245	        throw std::runtime_error(
246	          "CPU does not support DLM - cannot load DLM ROM image");
247	      }
248	      break;
249	
250	    case MEM_TYPE::RAM:
251	      read_binary_file(path, [this](const auto& data) {
252	        if (data.size() > platform.main_memory.data.size())
253	          throw std::runtime_error("RAM image size exceeds main memory size");
254	        std::copy(data.begin(), data.end(), platform.main_memory.data.begin());
255	      });
256	      break;
257	
258	    default:
259	      throw std::runtime_error("Unknown memory type");
260	    }
261	  }
