263	  void reset()
264	  {
265	    static constexpr int core_num = CPU::NDS_NHART;
266	    static constexpr int reset_val = (1 << core_num) - 1;
267	
268	    platform.resetn.write(0);
269	    auto saved = context_config;
270	    context_config = {};
271	    this->run(1);
272	    context_config = saved;
273	
274	    for (size_t i = 0; i < platform.reset_vector.size(); ++i)
275	      spdlog::info("hart {} reset vector: {:#x}", i,
276	                   (uint64_t) platform.reset_vector[i].read());
277	
278	    platform.resetn.write(reset_val);
279	
280	    if (context_config.continue_from)
281	      restore_context(context_config.dir);
282	  }
283	
284	  int run(const uint64_t max_cycles = std::numeric_limits<uint64_t>::max())
285	  {
286	    auto sa = memzeroed<struct sigaction>();
287	    sa.sa_handler = sigint_handler;
288	    sigemptyset(&sa.sa_mask);
289	
290	    auto oact = memzeroed<struct sigaction>();
291	    if (sigaction(SIGINT, &sa, &oact) == -1)
292	      perror("sigaction");
293	
294	    const auto restore_sigint = std::experimental::scope_exit{[&] {
295	      if (sigaction(SIGINT, &oact, nullptr) == -1)
296	        perror("sigaction");
297	    }};
298	
299	    // wait for debugger connections
300	    while (dtm_debug && !dtm.is_connected()) {
301	      dtm.try_accept_socket();
302	      if (ctrlc != 0) {
303	        return 130;
304	      }
305	      sleep(1);
306	    }
307	
308	    [[maybe_unused]]
309	    bool ctx_resuming = context_config.continue_from;
310	    [[maybe_unused]]
311	    bool ctx_triggered = false;
312	
313	    for (auto n = uint64_t{0}; n < max_cycles; ++n) {
314	
315	      if (ctx_resuming) [[unlikely]] {
316	        // Pull up PLIC interrupt signal at the first cycle of the resume
317	        platform.int_trigger.write(1);
318	        ctx_resuming = false;
319	        ctx_triggered = true;
320	      }
321	
322	      sc_core::sc_start(platform.clk.period());
323	
324	      trace_.on_cycle(cpu);
325	
326	      if (trace_.pipeview_wants_exit()) {
327	        spdlog::info("Pipeline viewer requested exit (Kanata loop window complete)");
328	        return 0;
329	      }
330	
331	      if (context_config.save_on_wfi && platform.wfi_signal.read() == true)
332	        [[unlikely]]
333	      {
334	        context_config.save(platform, cpu);
335	        spdlog::info("User save context");
336	        return 0;
337	      }
338	
339	      if (ctrlc != 0) {
340	        ctrlc = 0;
341	        spdlog::info("Ctrl+C PC: {:x}", get_current_pc());
342	        trace_.log_committed_pcs(cpu);
343	        return 130;
344	      }
345	
346	      if (ctx_triggered) [[unlikely]] {
347	        // Pull down the interrupt signal after 1 cycle
348	        platform.int_trigger.write(0);
349	        ctx_triggered = false;
350	      }
351	
352	      if (platform.sim_control.exits >= 0) {
353	        spdlog::info("sim_control: got exit {}, stopping",
354	                     platform.sim_control.exits);
355	        spdlog::info("Exit PC: {:x}", get_current_pc());
356	        trace_.log_committed_pcs(cpu);
357	        return platform.sim_control.exits;
358	      }
359	
360	      if (this->cpu.contextp()->gotFinish())
361	        return 0;
362	
363	      spdlog::trace("PC: {:x}", get_current_pc());
364	    }
365	    return 0;
366	  }
