22	enum class transfer_type : uint8_t
23	{
24	  idle = 0,
25	  busy = 1,
26	  nonseq = 2,
27	  seq = 3,
28	};
29	
30	template<std::size_t AddrWidth,
31	         std::size_t DataWidth,
32	         template<std::size_t>
33	         typename M2S,
34	         template<std::size_t>
35	         typename S2M>
36	struct interface
37	{
38	  using addr_type = vlpin<AddrWidth>;
39	  using data_type = vlpin<DataWidth>;
40	
41	  M2S<AddrWidth> haddr;
42	  M2S<3> hburst;
43	  M2S<4> hprot;
44	  M2S<3> hsize;
45	  M2S<2> htrans;
46	  M2S<DataWidth> hwdata;
47	  M2S<1> hwrite;
48	
49	  S2M<DataWidth> hrdata;
50	  S2M<1> hready;
51	  S2M<2> hresp;
52	};
53	
54	template<std::size_t AddrWidth, std::size_t DataWidth>
55	using signals = interface<AddrWidth, DataWidth, signaln, signaln>;
56	
57	// clang-format off
58	#define EXPAND_AHB_SIGNALS_NO_HREADY \
59	  X(haddr) X(hburst) X(hprot) X(hsize) X(htrans) X(hwdata) X(hwrite) \
60	  X(hrdata) X(hresp)
61	// clang-format on
62	
63	#define EXPAND_AHB_SIGNALS EXPAND_AHB_SIGNALS_NO_HREADY X(hready)
64	
65	template<std::size_t AddrWidth, std::size_t DataWidth>
66	struct manager : sc_core::sc_module,
67	                 ahb::interface<AddrWidth, DataWidth, out_port, in_port>
68	{
69	  using SC_CURRENT_USER_MODULE = manager<AddrWidth, DataWidth>;
70	  using interface = ahb::interface<AddrWidth, DataWidth, out_port, in_port>;
71	  using typename interface::addr_type;
72	  using typename interface::data_type;
73	  static constexpr auto max_hsize = std::bit_width(DataWidth / 8) - 1;
74	
75	  sc_core::sc_in<bool> clk{"clk"};
76	
77	  manager(const sc_core::sc_module_name& name)
78	      : sc_core::sc_module{name}
79	  {
80	    SC_THREAD(tick);
81	    this->sensitive << clk;
82	  }
83	
84	  struct transaction
85	  {
86	    addr_type addr = 0;
87	    data_type data = 0;
88	    bool is_write = false;
89	    enum class phase
90	    {
91	      address,
92	      data,
93	      okay,
94	      error,
95	    } phase = phase::address;
96	
97	    [[nodiscard]]
98	    auto is_busy() const -> bool
99	    {
100	      return this->phase == phase::address || this->phase == phase::data;
101	    }
102	  };
103	
104	  // TODO: make it private and only expose read-only public interface
105	  transaction txn = transaction{
106	    .addr = 0,
107	    .data = 0,
108	    .is_write = false,
109	    .phase = transaction::phase::okay,
110	  };
111	
112	  auto read(const vlpin<AddrWidth> addr)
113	  {
114	    // spdlog::trace("ahb::manager::read({:#x})", addr.to_uint64());
115	    assert(!this->txn.is_busy());
116	    this->txn = transaction{.addr = addr,
117	                            .data = 0,
118	                            .is_write = false,
119	                            .phase = transaction::phase::address};
120	  }
121	
122	  [[nodiscard]]
123	  auto write(const addr_type addr, const data_type data)
124	  {
125	    // spdlog::trace("ahb::manager::write({:#x}, {:#x})", addr.to_uint64(),
126	    // data.to_uint64());
127	    assert(!this->txn.is_busy());
128	    this->txn = transaction{.addr = addr,
129	                            .data = data,
130	                            .is_write = true,
131	                            .phase = transaction::phase::address};
132	  }
133	
134	  void issue()
135	  {
136	    this->haddr = this->txn.addr;
137	    this->hwrite = this->txn.is_write;
138	    this->hsize = max_hsize;
139	    this->hburst = 0;
140	    this->htrans = (uint8_t) transfer_type::nonseq;
141	    if (this->txn.is_write)
142	      this->hwdata = this->txn.data;
143	  }
144	
145	  void tick()
146	  {
147	    while (true) {
148	      wait(this->clk.posedge_event());
149	
150	      // NOTE: wait a delta cycle is necessary here.
151	      // In real hardware, DTM module sends AHB signals to DM, timing is handled
152	      // purely by hardware. But in our simulator, jtag_dtm and ahb_manager are
153	      // separated software module, thus incurring this timing synchronization.
154	      wait(sc_core::SC_ZERO_TIME);
155	
156	      if (this->txn.phase == transaction::phase::address) {
157	        this->issue();
158	        if (this->hready)
159	          this->txn.phase = transaction::phase::data;
160	      } else if (this->txn.phase == transaction::phase::data) {
161	        this->htrans = (uint8_t) transfer_type::idle;
162	        if (this->hready) {
163	          if (this->hresp.read().to_uint64() == 0) {
164	            this->txn.phase = transaction::phase::okay;
165	            if (!this->txn.is_write)
166	              this->txn.data = this->hrdata;
167	          } else {
168	            this->txn.phase = transaction::phase::error;
169	          }
170	        }
171	      }
172	    }
173	  }
174	};
